/**
 * Extract Slash Command Data - ROBUST VERSION
 * 
 * n8n webhook nodes can put form-urlencoded POST data in different places:
 *   - $json.body (parsed object)
 *   - $json directly (top-level fields)
 *   - $json.body as a string (needs parsing)
 * 
 * This code checks ALL possible locations with detailed logging.
 */

const webhookData = $('Slash Command Webhook').first().json;

console.log('📨 RAW WEBHOOK PAYLOAD:');
console.log('   Top-level keys:', Object.keys(webhookData).join(', '));

if (webhookData.body) {
  console.log('   body type:', typeof webhookData.body);
  if (typeof webhookData.body === 'object') {
    console.log('   body keys:', Object.keys(webhookData.body).join(', '));
  }
}

if (webhookData.headers) {
  const ct = webhookData.headers['content-type'] || webhookData.headers['Content-Type'] || 'unknown';
  console.log('   Content-Type:', ct);
}

function findField(fieldName) {
  if (webhookData[fieldName] !== undefined && webhookData[fieldName] !== '') {
    console.log(`   ✅ ${fieldName} found at top-level: "${webhookData[fieldName]}"`);
    return String(webhookData[fieldName]);
  }
  if (webhookData.body && typeof webhookData.body === 'object' && webhookData.body[fieldName] !== undefined) {
    console.log(`   ✅ ${fieldName} found in body: "${webhookData.body[fieldName]}"`);
    return String(webhookData.body[fieldName]);
  }
  if (webhookData.body && typeof webhookData.body === 'string') {
    const params = new URLSearchParams(webhookData.body);
    const val = params.get(fieldName);
    if (val) {
      console.log(`   ✅ ${fieldName} parsed from body string: "${val}"`);
      return val;
    }
  }
  if (webhookData.query && webhookData.query[fieldName]) {
    console.log(`   ✅ ${fieldName} found in query: "${webhookData.query[fieldName]}"`);
    return String(webhookData.query[fieldName]);
  }
  if (webhookData.params && webhookData.params[fieldName]) {
    console.log(`   ✅ ${fieldName} found in params: "${webhookData.params[fieldName]}"`);
    return String(webhookData.params[fieldName]);
  }
  console.log(`   ❌ ${fieldName} NOT FOUND in any location`);
  return '';
}

console.log('\n🔍 Searching for slash command fields:');

const userId = findField('user_id');
const userName = findField('user_name');
const channelId = findField('channel_id');
const channelName = findField('channel_name');
const responseUrl = findField('response_url');
const commandText = findField('text');
const teamDomain = findField('team_domain');

console.log('\n📊 EXTRACTED VALUES:');
console.log(`   👤 User: @${userName} (${userId})`);
console.log(`   📺 Channel: #${channelName} (${channelId})`);
console.log(`   🔗 Response URL: ${responseUrl ? responseUrl.substring(0, 60) + '...' : 'MISSING'}`);
console.log(`   📝 Text: "${commandText}"`);

if (!userId) {
  console.error('🚨 CRITICAL: No user_id found! Full payload dump:');
  console.error(JSON.stringify(webhookData, null, 2).substring(0, 2000));
}

return [{
  json: {
    userId,
    userName,
    channelId,
    channelName,
    responseUrl,
    commandText,
    teamDomain,
    _raw: webhookData
  }
}];

/**
 * Merge User Context - ROBUST VERSION
 * Handles cases where email scope might be missing
 */

const slashData = $('Extract Slash Command Data').first().json;
const slackResponse = $input.first().json;

console.log('👤 Slack API Response keys:', Object.keys(slackResponse).join(', '));
console.log('   ok:', slackResponse.ok);

const userObj = slackResponse.user || {};
const userProfile = userObj.profile || {};
let userEmail = userProfile.email || userObj.email || '';

if (!userEmail && slackResponse.profile) {
  userEmail = slackResponse.profile.email || '';
}

const realName = userObj.real_name || userProfile.real_name || slashData.userName || 'there';

console.log('📧 Email extraction:');
console.log('   user.profile.email:', userProfile.email || '(not present)');
console.log('   user.email:', userObj.email || '(not present)');
console.log('   Final email:', userEmail || '(NONE - bot may lack users:read.email scope)');
console.log('   Real name:', realName);
console.log('   Channel ID:', slashData.channelId);
console.log('   Response URL:', slashData.responseUrl ? 'Present' : 'MISSING');

if (!userEmail) {
  console.warn('⚠️ No email found. Possible fixes:');
  console.warn('   1. Add "users:read.email" scope to your Slack bot');
  console.warn('   2. Reinstall the app after adding the scope');
}

return [{
  json: {
    userId: slashData.userId,
    userName: slashData.userName,
    realName: realName,
    userEmail: userEmail,
    channelId: slashData.channelId,
    channelName: slashData.channelName,
    responseUrl: slashData.responseUrl,
    commandText: slashData.commandText,
    teamDomain: slashData.teamDomain
  }
}];

