const topTier = sorted.slice(0, tierSize);
const midTier = sorted.slice(tierSize, tierSize * 2);
const bottomTier = sorted.slice(tierSize * 2);

console.log(`  Top tier (${topTier.length} accounts): Revenue range $${topTier[topTier.length - 1]?.annualRevenue || 0} - $${topTier[0]?.annualRevenue || 0}`);
console.log(`  Mid tier (${midTier.length} accounts): Revenue range $${midTier[midTier.length - 1]?.annualRevenue || 0} - $${midTier[0]?.annualRevenue || 0}`);
console.log(`  Bottom tier (${bottomTier.length} accounts): Revenue range $${bottomTier[bottomTier.length - 1]?.annualRevenue || 0} - $${bottomTier[0]?.annualRevenue || 0}`);

// Take 5 from each tier
const selected = [
  ...topTier.slice(0, 5),
  ...midTier.slice(0, 5),
