 */

const aiOutput = $input.first().json.output || $input.first().json.text || $input.first().json.response || JSON.stringify($input.first().json);

console.log('🔍 Parsing deep dive AI response...');

// Try to extract JSON from the response
let parsed = null;

// Try direct JSON parse
try {
  parsed = JSON.parse(aiOutput);
} catch (e) {
  // Try to find JSON block in the text
  const jsonMatch = aiOutput.match(/\{[\s\S]*?"account_name"[\s\S]*?\}/i);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      console.log('⚠️ Could not parse JSON from AI response, using raw text');
    }
  }
}

if (parsed) {
  console.log(`✅ Parsed deep dive for: ${parsed.account_name || 'unknown'}`);
  return [{ json: parsed }];
} else {
  // Return a structured placeholder with what we can extract
  console.log('⚠️ Returning raw AI output as fallback');
  return [{ json: { account_name: 'Parse Error', raw_output: aiOutput, meetings_90d: 0, meeting_cadence: 'unknown', meeting_ratio: 0, unique_contacts: 0, exec_contacts: 0, exec_ratio: 0, committee_formed: false, new_stakeholders_last_30d: 0, email_responsiveness: 0, exec_entry_timing: 'unknown', engagement_arc: 'unknown' } }];
}

/**
 * Aggregate Deep Dive Results
 * Collects all deep dive results from the loop into a single array.
 */

const items = $input.all();

console.log(`📊 Aggregating ${items.length} deep dive results`);

const deepDiveResults = items
  .filter(item => !item.json._empty && item.json.account_name !== 'Parse Error')
  .map(item => item.json);

console.log(`✅ Aggregated ${deepDiveResults.length} valid deep dive results`);

deepDiveResults.forEach((dd, idx) => {
  console.log(`  ${idx + 1}. ${dd.account_name} - Cadence: ${dd.meeting_cadence} - Arc: ${dd.engagement_arc}`);
});

return [{ json: { deepDiveResults, totalDeepDives: deepDiveResults.length } }];

/**
 * Prepare data for the Win Pattern Fingerprint AI analysis.
 * Merges winners, losers, and deep dive data into a single prompt-ready payload.
 */

const items = $input.all();
console.log(`📊 Merge All Data: Processing ${items.length} inputs`);

const output = {
  winners: [],
  losers: [],
  deepDiveResults: [],
  totalWinners: 0,
  totalLosers: 0,
  totalDeepDives: 0
};

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  console.log(`  Input ${i + 1}:`, Object.keys(item));

  if (item.winners) {
    output.winners = item.winners || [];
    output.totalWinners = item.totalWinners || 0;
    console.log(`✅ Found winners: ${output.totalWinners}`);
  }

  if (item.losers) {
    output.losers = item.losers || [];
    output.totalLosers = item.totalLosers || 0;
    console.log(`✅ Found losers: ${output.totalLosers}`);
  }

  if (item.deepDiveResults) {
    output.deepDiveResults = item.deepDiveResults || [];
    output.totalDeepDives = item.totalDeepDives || 0;
    console.log(`✅ Found deep dives: ${output.totalDeepDives}`);
  }
}

console.log(`\n📦 Merged Data Summary:`);
console.log(`   🏆 Winners: ${output.totalWinners} accounts`);
console.log(`   ❌ Losers: ${output.totalLosers} accounts`);
console.log(`   🔍 Deep Dives: ${output.totalDeepDives} accounts`);

return [{ json: output }];

