// Convert markdown-style formatting to HTML
function markdownToHtml(text) {
  let html = text
    // Bold
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    // Italic
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    // Headers with emoji
    .replace(/^(\ud83c[\udf00-\udfff]|\ud83d[\udc00-\ude4f]|\ud83d[\ude80-\udeff]|[\u2600-\u26FF]|[\u2700-\u27BF]|\u2696|\ud83d\udeab)\s*(.+)$/gm, '<h2 style="color: #1f2937; font-size: 20px; margin: 24px 0 12px 0; border-bottom: 2px solid #7c3aed; padding-bottom: 8px;">$1 $2</h2>')
    // Tables
    .replace(/\|(.+)\|/g, function(match) {
      const cells = match.split('|').filter(c => c.trim());
      if (cells.every(c => /^[\s-:]+$/.test(c))) return ''; // separator row
      const isHeader = cells.every(c => /^\s*[A-Z]/.test(c.trim()));
      const tag = isHeader ? 'th' : 'td';
      const style = isHeader
        ? 'style="padding: 10px 12px; background-color: #7c3aed; color: white; font-size: 12px; text-align: left; font-weight: 600;"'
        : 'style="padding: 10px 12px; border-bottom: 1px solid #e5e7eb; font-size: 13px;"';
      return '<tr>' + cells.map(c => `<${tag} ${style}>${c.trim()}</${tag}>`).join('') + '</tr>';
    })
    // Bullet points
    .replace(/^-\s+(.+)$/gm, '<li style="margin-bottom: 6px; font-size: 14px;">$1</li>')
    .replace(/^(\d+)\.\s+(.+)$/gm, '<li style="margin-bottom: 8px; font-size: 14px;"><strong>$1.</strong> $2</li>')
    // Newlines
    .replace(/\n\n/g, '</p><p style="margin: 12px 0; font-size: 14px; line-height: 1.6; color: #374151;">')
    .replace(/\n/g, '<br>');

  // Wrap table rows
  if (html.includes('<tr>')) {
    html = html.replace(/(<tr>.*?<\/tr>)+/gs, '<table style="width: 100%; border-collapse: collapse; margin: 16px 0; border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">$&</table>');
  }

  // Wrap list items
  if (html.includes('<li')) {
    html = html.replace(/(<li[^>]*>.*?<\/li>)+/gs, '<ul style="margin: 12px 0; padding-left: 24px;">$&</ul>');
  }

  return html;
}

